43	final class BluetoothManagerImpl: NSObject {
44	
45	    private enum Consts {
46	        static let radiaCodeServiceCBUUID = CBUUID(string: "E63215E5-7003-49D8-96B0-B024798FB901")
47	    }
48	
49	    private let centralManager: CBCentralManager
50	
51	    private let searchingObserver: PassthroughSubject<Bool, Never> = .init()
52	    private let bleStatusObserver: CurrentValueSubject<Bool, Never> = .init(false)
53	    private let devicesObserver: PassthroughSubject<RadiaCode, Never> = .init()
54	    var bluetoothStatus: CurrentValueSubject<BluetoothStatus, Never> = .init(.unknown)
55	
56	    private var cancellable: Set<AnyCancellable> = .init()
57	    private var reconnectionCancellable: AnyCancellable?
58	    private var disconnectContinuation: CheckedContinuation<Void, Error>?
59	
60	    private let bleQueue: DispatchQueue = .init(label: "com.radiacode.bluetooth.scan", qos: .background)
61	
62	    override init() {
63	        centralManager = CBCentralManager(delegate: nil, queue: bleQueue, options: nil)
64	        super.init()
65	        centralManager.delegate = self
66	        setupObservers()
67	    }
68	}
