221	        let versionResult = await connectedDevice.send(command: FirmwareCommand.GetVersion())
222	        if case .success(let response) = versionResult {
223	            analyticsEngine?.setupUser(deviceId: appInfo.uniqueDeviceId, radiaCodeDevice: connectedDevice.identifier, firmware: response.target.version)
224	            connectedDevice.firmware.version = response
