8	import Foundation
9	
10	/// Запрос команды
11	struct BluetoothCommandRequest {
12	    /// Регистр основной команды
13	    let type: BluetoothCommandType?
14	    /// Посылаемая команда
15	    let command: BluetoothCommandOperation
16	    /// Дополнительные данные
17	    let payload: [UInt8]?
18	    
19	    /// Инициализатор
20	    /// - Parameters:
21	    ///   - type: Регистр основной команды
22	    ///   - command: Посылаемая команда
23	    ///   - payload: Дополнительные данные
24	    init(type: BluetoothCommandType? = nil, command: BluetoothCommandOperation, payload: [UInt8]? = nil) {
25	        self.type = type
26	        self.command = command
27	        self.payload = payload
28	    }
29	}
30	
31	protocol BluetoothCommandRequestProvider {
32	
33	    var request: BluetoothCommandRequestBuilder<BluetoothCommandRequest> { get }
34	}
35	
36	struct BluetoothCommandRequestBuilder<T> {
37	    
38	    public typealias Builder = ([UInt8]) -> [Data]
39	
40	    private var build: Builder
41	
42	    public init(builder: @escaping Builder) {
43	        build = builder
44	    }
45	
46	    public func convert(_ request: [UInt8]) -> [Data] {
47	        return build(request)
48	    }
49	}
50	
51	protocol BluetoothRequestPackage: BluetoothCommandRequestProvider {
52	    /// Запрос
53	    var request: BluetoothCommandRequest { get }
54	    /// Данные запроса
55	    var commandData: [UInt8] { get }
56	}
57	
58	extension BluetoothRequestPackage where Self: BluetoothCommandRequestConfigurator {
59	
60	    var commandData: [UInt8] {
61	        var result: [UInt8] = []
62	        
63	        if let type = request.type {
64	            result += type.rawValue.asBytes
65	        }
66	        result += request.command.rawValue.asBytes
67	         
68	        if request.type == .writeVirtualString {
69	            if let payloadLength = request.payload?.count {
70	                result += UInt32(payloadLength).asBytes
71	            } else {
72	                result += [0]
73	            }
74	        }
75	        
76	        if let payload = request.payload {
77	            result += payload
78	        }
79	            
80	        return result
81	    }
82	    
83	    func requestPackage() -> [Data] {
84	        let data = request.convert(commandData)
85	        return data
86	    }
87	}
88	
89	protocol BluetoothCommandRequestConfigurator {
90	    
91	    func requestPackage() -> [Data]
92	}
